bool checkPassword(String pass) {
  if (pass == '1234') {
    return true;
  } else {
    return false;
  }
}

void main() {
  bool granted = checkPassword('0000');

  if (granted) {
    print('Unlocked');
  } else {
    print('Locked out!');
  }
}
